using CollegeManagementSystem.Data;using CollegeManagementSystem.Data.Entities;using Microsoft.AspNetCore.Mvc;using Microsoft.EntityFrameworkCore;namespace CollegeManagementSystem.Controllers;[Route("api/[controller]")][ApiController]public class CoursesController(AppDbContext db) : ControllerBase{//     private AppDbContext _db;////     public CoursesController(AppDbContext db)//     {//         this._db = db;//     }    [HttpGet]    public async Task<IActionResult> GetAllCourses()    {        var allCourses = await db.Courses.ToListAsync();        var count = allCourses.Count;        return Ok(new { count, allCourses });    }    [HttpGet("{id}")]    public async Task<IActionResult> GetCourseWithModules(int id)    {        var course = await db.Courses.Where(c => c.Id == id).Select(c => new        {            c.Id, c.Name, c.Duration,            c.Modules        }).FirstOrDefaultAsync();        return Ok(course);    }    [HttpGet("{id}/modules")]    public async Task<IActionResult> GetCourseModules(int id)    {        var modules = await db.Courses.Where(c => c.Id == id).Select(c => new { c.Id, c.Name, c.Modules })            .ToListAsync();        // var modules = await db.Modules.Where(m => m.CourseId == id);        return Ok(modules);    }    [HttpPost("/add")]    public IActionResult AddCourse(Course course)    {        db.Courses.Add(course);        db.SaveChanges();        return Ok("Course Added");    }}